//stack-percent.js

import { StackLayout } from './stack-layout';

var proto = StackLayout.prototype;

/**
 * Convert the stack data to 100% stack data
 * @param  {Array} data        [description]
 * @param  {Function} keyAccessor [description]
 */
proto.toPercent = function(data, keyAccessor) {
    var layout = this,
        list = layout._list;

    data.forEach(d => {
        var key = keyAccessor(d),
            entry = list.get(key),
            max = entry && entry[1]; //FEATURES_BAR_19 entry is null

        if (!isNaN(max) && max != null && max != 0) {
            d.y0 /= max / 100;
            d.y /= max / 100;
        }
    });
};
